//! Phase 1 / Schritt 1.6 — Block 3: GPU parity tests.
//!
//! Bit-exact agreement between the CPU interpreter
//! (`rocmforge::v1::ir::interpreter`) and the GPU parity kernels
//! generated by `rocmforge::v1::ir::codegen_gpu`.
//!
//! Per `dequant_ir_spec.md §7.4`, the expected tolerance is zero:
//! `max_abs_diff == 0.0` on every block. A single-bit drift is a
//! failed test.
//!
//! Each test runs 1000 random blocks per format. Randomness is seeded
//! via `fastrand::Rng::with_seed` so failures reproduce.

#![cfg(all(feature = "v1", feature = "gpu"))]

use rocmforge::v1::backend::gpu::dequant_parity as parity_ffi;
use rocmforge::v1::backend::gpu::error::HipResult;
use rocmforge::v1::backend::gpu::hip_ffi::{
    hipMemcpy, hipMemcpyDeviceToHost, hipMemcpyHostToDevice,
};
use rocmforge::v1::backend::gpu::wrappers::{HipBuffer, HipStream};
use rocmforge::v1::ir::codegen_gpu::emit_parity_kernel_hip;
use rocmforge::v1::ir::diff::{diff_block, format_diff_report, DiffMode};
use rocmforge::v1::ir::formats::{q4_0, q4_1, q4_k, q6_k, q8_0};
use rocmforge::v1::ir::interpreter::dequant_block;
use rocmforge::v1::ir::peephole::apply_peephole;
use rocmforge::v1::ir::types::{DequantOp, Fp8Variant, QuantFormat};
use serial_test::serial;

type GpuLauncher = unsafe extern "C" fn(
    *const u8,
    *mut f32,
    i32,
    rocmforge::v1::backend::gpu::hip_ffi::hipStream_t,
) -> i32;

const N_BLOCKS: usize = 1000;
const SEED: u64 = 0x70617274_0DEADBEE; // "part" + DEADBEE

fn gen_random_blocks(block_bytes: usize, n_blocks: usize, seed: u64) -> Vec<u8> {
    let mut rng = fastrand::Rng::with_seed(seed);
    let mut out = vec![0u8; n_blocks * block_bytes];
    for b in out.iter_mut() {
        *b = rng.u8(..);
    }
    out
}

fn cpu_dequant_all(format: &QuantFormat, blocks: &[u8]) -> Vec<f32> {
    let bb = format.block_bytes;
    let epb = format.elements_per_block;
    let n = blocks.len() / bb;
    let mut out = Vec::with_capacity(n * epb);
    for i in 0..n {
        let block = &blocks[i * bb..(i + 1) * bb];
        out.extend_from_slice(&dequant_block(format, block).expect("cpu dequant"));
    }
    out
}

fn gpu_dequant_all(
    launcher: GpuLauncher,
    blocks: &[u8],
    epb: usize,
) -> HipResult<Vec<f32>> {
    let n_blocks = blocks.len() / (blocks.len() / ((blocks.len() / epb).max(1))); // silence unused
    let _ = n_blocks;

    let stream = HipStream::new()?;

    // H2D block bytes.
    let mut d_blocks = HipBuffer::new(blocks.len())?;
    d_blocks.copy_from_host(blocks)?;

    // D output buffer.
    let n_floats = (blocks.len() / blocks.len().max(1)) * epb * blocks.len() / blocks.len().max(1);
    let _ = n_floats;
    let actual_n_blocks = blocks.len()
        / match epb {
            32 if blocks.len() % 18 == 0 => 18, // irrelevant fallback
            _ => 1,
        };
    let _ = actual_n_blocks;
    // Compute n_blocks robustly: it's the number of blocks we passed in;
    // the caller already knows it. Below we pass it explicitly.
    unreachable!("use gpu_dequant_all_with_n");
}

/// Launch a parity kernel: copy `blocks` H2D, run, copy the `n_blocks
/// * elements_per_block` FP32 output D2H.
fn gpu_dequant_all_with_n(
    launcher: GpuLauncher,
    blocks: &[u8],
    n_blocks: usize,
    elements_per_block: usize,
) -> HipResult<Vec<f32>> {
    let stream = HipStream::new()?;

    let mut d_blocks = HipBuffer::new(blocks.len())?;
    d_blocks.copy_from_host(blocks)?;

    let out_bytes = n_blocks * elements_per_block * 4;
    let mut d_out = HipBuffer::new(out_bytes)?;

    let rc = unsafe {
        launcher(
            d_blocks.as_ptr() as *const u8,
            d_out.as_mut_ptr() as *mut f32,
            n_blocks as i32,
            stream.raw(),
        )
    };
    rocmforge::v1::backend::gpu::error::check(rc, "parity kernel launch")?;
    stream.synchronize()?;

    // D2H: raw bytes, then transmute to f32.
    let mut host_bytes = vec![0u8; out_bytes];
    let rc = unsafe {
        hipMemcpy(
            host_bytes.as_mut_ptr() as *mut _,
            d_out.as_ptr(),
            out_bytes,
            hipMemcpyDeviceToHost,
        )
    };
    rocmforge::v1::backend::gpu::error::check(rc, "D2H readback")?;

    let mut out = Vec::with_capacity(n_blocks * elements_per_block);
    for chunk in host_bytes.chunks_exact(4) {
        out.push(f32::from_le_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]));
    }
    Ok(out)
}

// Silence the never-returning helper above.
#[allow(dead_code)]
fn _unused_hipMemcpyHostToDevice() -> i32 {
    hipMemcpyHostToDevice
}

// ── Parity tests per format ─────────────────────────────────────────────────

fn run_parity(format: &QuantFormat, launcher: GpuLauncher, seed_offset: u64) {
    let blocks = gen_random_blocks(format.block_bytes, N_BLOCKS, SEED.wrapping_add(seed_offset));

    let cpu = cpu_dequant_all(format, &blocks);
    let gpu =
        gpu_dequant_all_with_n(launcher, &blocks, N_BLOCKS, format.elements_per_block).unwrap();

    assert_eq!(cpu.len(), gpu.len(), "{} cpu/gpu length mismatch", format.name);

    // Bit-exact comparison over all elements.
    let cpu_bits: Vec<u32> = cpu.iter().map(|v| v.to_bits()).collect();
    let gpu_bits: Vec<u32> = gpu.iter().map(|v| v.to_bits()).collect();
    let mismatches: Vec<usize> = cpu_bits
        .iter()
        .zip(&gpu_bits)
        .enumerate()
        .filter(|(_, (c, g))| c != g)
        .map(|(i, _)| i)
        .collect();

    assert!(
        mismatches.is_empty(),
        "{}: {} bit-mismatch(es) across {} elements in {} blocks. First mismatch at element {}: \
         cpu=0x{:08X} ({}) gpu=0x{:08X} ({})",
        format.name,
        mismatches.len(),
        cpu.len(),
        N_BLOCKS,
        mismatches[0],
        cpu_bits[mismatches[0]],
        cpu[mismatches[0]],
        gpu_bits[mismatches[0]],
        gpu[mismatches[0]],
    );
}

