// ── Denormal parity: FTZ=off verification ───────────────────────────────────

/// Build a Q4_0 block whose dequant output lands in the FP16/FP32
/// denormal range. Uses a very small `d` so `d * (nibble - 8)` is
/// below 2^-14 (FP16 smallest normal) for most nibbles. If either side
/// flushes to zero while the other doesn't, the parity check breaks.
fn build_denormal_q4_0_block() -> Vec<u8> {
    let mut block = vec![0u8; 18];
    // d = 2^-20 (≈ 9.5e-7). Multiplied by nibble-8 ∈ [-8, 7] gives
    // magnitudes 2^-23..2^-20 — solidly in the FP16 denormal range.
    let d = half::f16::from_f32(2f32.powi(-20));
    block[0..2].copy_from_slice(&d.to_bits().to_le_bytes());
    // Varied nibbles so we hit both sides of zero.
    for i in 2..18 {
        block[i] = 0x73; // low=3 (centred -5), high=7 (centred -1)
    }
    block
}

#[test]
#[serial]
fn test_parity_denormal() {
    let fmt = q4_0();
    let block = build_denormal_q4_0_block();
    let cpu = dequant_block(&fmt, &block).unwrap();
    let gpu =
        gpu_dequant_all_with_n(parity_ffi::rocmforge_launch_dequant_q4_0_parity, &block, 1, 32)
            .unwrap();

    // Any element in FP32 denormal range (< 2^-126) flushed to 0 on one
    // side would break this; expect bit-exact equality on both.
    for (i, (&c, &g)) in cpu.iter().zip(gpu.iter()).enumerate() {
        assert_eq!(
            c.to_bits(),
            g.to_bits(),
            "denormal parity failed at element {i}: cpu=0x{:08X} ({}) gpu=0x{:08X} ({}) — \
             FTZ=off not effective on one side",
            c.to_bits(),
            c,
            g.to_bits(),
            g
        );
    }
}

#[test]
#[serial]
fn test_parity_with_diff_report() {
    // Smoke: run the Q4_K parity, feed the output through the Diff
    // tool, and print the report for visual inspection.
    let fmt = q4_k();
    let blocks = gen_random_blocks(fmt.block_bytes, 3, SEED ^ 0xDEAD);
    let cpu = cpu_dequant_all(&fmt, &blocks);
    let gpu =
        gpu_dequant_all_with_n(parity_ffi::rocmforge_launch_dequant_q4_k_parity, &blocks, 3, 256)
            .unwrap();

    let diffs = diff_block(&cpu, &gpu, DiffMode::BitExact);
    let report = format_diff_report("Q4_K", &diffs, cpu.len());
    println!("{report}");
    assert!(diffs.is_empty(), "expected bit-exact parity over 3 blocks");
}

// ── Peephole consistency ────────────────────────────────────────────────────

#[test]
fn test_peephole_mul_add_to_fma() {
    // Program: MulF32(a, b, T) + AddF32(T, c, W). Peephole must fuse.
    let program = vec![
        DequantOp::LoadBytes {
            offset: 0,
            count: 2,
            reg: 10,
        },
        DequantOp::MulF32 {
            a: 0,
            b: 1,
            dst: 100,
        },
        DequantOp::AddF32 {
            a: 100,
            b: 2,
            dst: 101,
        },
        DequantOp::DowncastToFP8 {
            src: 101,
            dst: 102,
            variant: Fp8Variant::E4M3,
            saturate: true,
        },
        DequantOp::StoreFP8 {
            src: 102,
            variant: Fp8Variant::E4M3,
            lds_offset_expr: "i".into(),
        },
    ];
    let out = apply_peephole(&program);
    // Expect: LoadBytes, FmaF32, DowncastToFP8, StoreFP8 — one less op.
    assert_eq!(out.len(), program.len() - 1, "one op should be fused");
    match &out[1] {
        DequantOp::FmaF32 { a, b, c, dst } => {
            assert_eq!(*a, 0);
            assert_eq!(*b, 1);
            assert_eq!(*c, 2);
            assert_eq!(*dst, 101);
        }
        other => panic!("expected FmaF32, got {:?}", other),
    }
}

#[test]
fn test_peephole_no_fusion_when_intermediate_reused() {
    // Program: MulF32(..., T), AddF32(T, ..., W), MulF32(T, ..., X)
    // T is reused below — peephole must NOT fuse.
    let program = vec![
        DequantOp::LoadBytes {
            offset: 0,
            count: 2,
            reg: 10,
        },
        DequantOp::MulF32 {
            a: 0,
            b: 1,
            dst: 100,
        },
        DequantOp::AddF32 {
            a: 100,
            b: 2,
            dst: 101,
        },
        // T = r100 reused here → must not fuse.
        DequantOp::MulF32 {
            a: 100,
            b: 3,
            dst: 102,
        },
        DequantOp::DowncastToFP8 {
            src: 101,
            dst: 103,
            variant: Fp8Variant::E4M3,
            saturate: true,
        },
        DequantOp::StoreFP8 {
            src: 103,
            variant: Fp8Variant::E4M3,
            lds_offset_expr: "i".into(),
        },
    ];
    let out = apply_peephole(&program);
    assert_eq!(
        out.len(),
        program.len(),
        "reused intermediate must prevent fusion"
    );
}

#[test]
fn test_peephole_is_no_op_on_phase1_formats() {
    // All five Phase-1 formats already use FmaF32 where fusion matters,
    // so the shared peephole pass must leave them unchanged.
    for fmt in [q4_0(), q4_1(), q8_0(), q4_k(), q6_k()] {
        let before = fmt.dequant_program.clone();
        let after = apply_peephole(&before);
        assert_eq!(
            before, after,
            "{} program changed by peephole — unexpected fusion",
            fmt.name
        );
    }
}

// ── Codegen smoke ───────────────────────────────────────────────────────────

#[test]
fn test_codegen_emit_kernel_shape() {
    // All five format emitters should yield non-empty source containing
    // the expected extern-C kernel signature.
    for fmt in [q4_0(), q4_1(), q8_0(), q4_k(), q6_k()] {
        let src = emit_parity_kernel_hip(&fmt);
        assert!(
            src.contains("__global__"),
            "{}: missing __global__",
            fmt.name
        );
        assert!(
            src.contains(&format!(
                "rocmforge_dequant_{}_parity",
                fmt.name.to_lowercase()
            )),
            "{}: missing named kernel",
            fmt.name
        );
    }
}
